// src/app/login/page.tsx
'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import {
  Box, Button, Card, CardContent, TextField,
  Typography, Snackbar, Alert
} from '@mui/material';

export default function LoginPage() {
  const router = useRouter();
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [snackbar, setSnackbar] = useState({ open: false, message: '', severity: 'error' });

  const handleLogin = () => {
    const correctUsername = process.env.NEXT_PUBLIC_POS_USER || 'admin';
    const correctPassword = process.env.NEXT_PUBLIC_POS_PASSWORD || '1234';

    if (username === correctUsername && password === correctPassword) {
      localStorage.setItem('auth_token', 'glossy-secret');
      router.push('/home');
    } else {
      setSnackbar({ open: true, message: 'ชื่อผู้ใช้หรือรหัสผ่านไม่ถูกต้อง', severity: 'error' });
    }
  };

  useEffect(() => {
    const token = localStorage.getItem('auth_token');
    if (token === 'glossy-secret') {
      router.push('/home');
    }
  }, []);

  return (
    <Box minHeight="100vh" display="flex" justifyContent="center" alignItems="center" bgcolor="#f5f5f5">
      <Card sx={{ width: 360, borderRadius: 4 }}>
        <CardContent>
          <Typography variant="h5" fontWeight="bold" align="center" gutterBottom>
            🔐 เข้าสู่ระบบหน้าร้าน
          </Typography>

          <TextField
            label="ชื่อผู้ใช้"
            value={username}
            onChange={(e) => setUsername(e.target.value)}
            fullWidth
            margin="normal"
          />
          <TextField
            label="รหัสผ่าน"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            fullWidth
            margin="normal"
          />

          <Button
            variant="contained"
            color="primary"
            fullWidth
            sx={{ mt: 2 }}
            onClick={handleLogin}
          >
            🚀 เข้าสู่ระบบ
          </Button>
        </CardContent>
      </Card>

      <Snackbar
        open={snackbar.open}
        autoHideDuration={3000}
        anchorOrigin={{ vertical: 'top', horizontal: 'right' }}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
      >
        <Alert
          severity={snackbar.severity as any}
          sx={{ width: '100%' }}
          onClose={() => setSnackbar({ ...snackbar, open: false })}
        >
          {snackbar.message}
        </Alert>
      </Snackbar>
    </Box>
  );
}
